from dataclasses import dataclassfrom collections.abc import Iteratorfrom criresviz.database.loader import load_settings_databasefrom .order import Orderfrom .detector import Detector@dataclass(slots=True)class CRIRESSetting:    name: str    band: str    reference_wavelength: float    orders: list[Order]        '''    Properties    '''        @property    def wavelength_range(self):        return (            min(order.wavelength_min for order in self.orders),            max(order.wavelength_max for order in self.orders),        )        '''    Methods    '''    @classmethod    def from_name(cls, name: str):        """        Create a CRIRESSetting from its setting name.        Parameters        ----------        name : str            CRIRES+ setting name (e.g. "M4368").        Returns        -------        CRIRESSetting        """        database = load_settings_database()        info = database[name]        orders = []                for order_number, order_info in info["orders"].items():                    detector1 = Detector(                number=1,                wavelength_min=order_info["detector1"]["min"],                wavelength_max=order_info["detector1"]["max"],            )                    detector2 = Detector(                number=2,                wavelength_min=order_info["detector2"]["min"],                wavelength_max=order_info["detector2"]["max"],            )                    detector3 = Detector(                number=3,                wavelength_min=order_info["detector3"]["min"],                wavelength_max=order_info["detector3"]["max"],            )                    orders.append(                Order(                    number=int(order_number),                    detector1=detector1,                    detector2=detector2,                    detector3=detector3,                )            )                    orders = sorted(            orders,            key=lambda order: order.number,            reverse=True,            )        return cls(            name=name,            band=info["band"],            reference_wavelength=info["reference_wavelength"],            orders=orders        )        ##############################################        def __iter__(self) -> Iterator[Order]:        return iter(self.orders)    ##############################################    def get_order(self, number: int) -> Order:            for order in self.orders:                if order.number == number:                return order            raise ValueError(            f"Order {number} not found."        )    ##############################################        def __str__(self):            return (            "CRIRES+ Setting\n"            "──────────────────────────────\n"            f"Name:                 {self.name}\n"            f"Band:                 {self.band}\n"            f"Reference wavelength:   {self.reference_wavelength:.3f} μm\n"                        f"Orders:               {len(self.orders)}\n"            f"Wavelength range:     "            f"{self.wavelength_range[0]:.3f}–"            f"{self.wavelength_range[1]:.3f} μm"        )        ##############################################            def plot(self, ax=None):        """        Plot the CRIRES+ wavelength coverage for this setting.        """            from criresviz.plotting import plot_setting            return plot_setting(            self,            ax=ax,        )